    35→/**
    36→ * JAAS configuration parser that constructs a JAAS configuration object with a single
    37→ * login context from the Kafka configuration option {@link SaslConfigs#SASL_JAAS_CONFIG}.
    38→ * <p/>
    39→ * JAAS configuration file format is described <a href="http://docs.oracle.com/javase/8/docs/technotes/guides/security/jgss/tutorials/LoginConfigFile.html">here</a>.
    40→ * The format of the property value is:
    41→ * <pre>
    42→ * {@code
    43→ *   <loginModuleClass> <controlFlag> (<optionName>=<optionValue>)*;
    44→ * }
    45→ * </pre>
    46→ */
    47→class JaasConfig extends Configuration {
    48→
    49→    private final String loginContextName;
    50→    private final List<AppConfigurationEntry> configEntries;
    51→
    52→    public JaasConfig(String loginContextName, String jaasConfigParams) {
    53→        StreamTokenizer tokenizer = new StreamTokenizer(new StringReader(jaasConfigParams));
    54→        tokenizer.slashSlashComments(true);
    55→        tokenizer.slashStarComments(true);
    56→        tokenizer.wordChars('-', '-');
    57→        tokenizer.wordChars('_', '_');
    58→        tokenizer.wordChars('$', '$');
    59→
    60→        try {
    61→            configEntries = new ArrayList<>();
    62→            while (tokenizer.nextToken() != StreamTokenizer.TT_EOF) {
    63→                configEntries.add(parseAppConfigurationEntry(tokenizer));
    64→            }
    65→            if (configEntries.isEmpty())
    66→                throw new IllegalArgumentException("Login module not specified in JAAS config");
    67→
    68→            this.loginContextName = loginContextName;
    69→
    70→        } catch (IOException e) {
    71→            throw new KafkaException("Unexpected exception while parsing JAAS config");
    72→        }
    73→    }
    74→
    75→    @Override
    76→    public AppConfigurationEntry[] getAppConfigurationEntry(String name) {
    77→        if (this.loginContextName.equals(name))
    78→            return configEntries.toArray(new AppConfigurationEntry[0]);
    79→        else
    80→            return  null;
    81→    }
